import cn from 'clsx'
import PropTypes from 'prop-types'
import React from 'react'

export interface NavigationPanelProps {
  /**
   * Navigation elements.
   */
  children: React.ReactNode
  /**
   * CSS class name
   */
  className?: string
}

export const NavigationPanel: React.FC<NavigationPanelProps> = props => {
  const { children, className } = props
  return (
    <div className={cn('kyokuya-post-navigation-panel', className)}>
      <div className="kyokuya-post-navigation-panel__nav-wrapper">
        {children}
      </div>
    </div>
  )
}

NavigationPanel.propTypes = {
  children: PropTypes.node.isRequired,
  className: PropTypes.string,
}

NavigationPanel.displayName = 'KyokuyaLayoutPostNavigationPanel'
export default NavigationPanel
